#!/usr/bin/env python3
import os, base64
b64 = ''
path = "app\\api\\forecast\\route.ts"
path = path.replace("\\\\", os.sep).replace("\\", os.sep)
with open(path, "wb") as f:
    f.write(base64.b64decode(b64))
print("Done — git add . && git commit -m \"Fix forecast duplicate year\" && vercel --prod")
